const html = query;
if (!html || html.trim().length < 50) {
  return 'ERROR: No valid HTML provided. Please pass the complete HTML email code to this tool.';
}
const issues = [];
const warnings = [];
const passed = [];
if (/<html[^>]*lang\s*=/i.test(html)) { passed.push('HTML lang attribute present'); } else { issues.push('Missing lang attribute on <html> tag'); }
const headingMatches = [...html.matchAll(/<h([1-6])[^>]*>/gi)];
const headingLevels = headingMatches.map(m => parseInt(m[1]));
let headingOk = true;
for (let i = 1; i < headingLevels.length; i++) {
  if (headingLevels[i] > headingLevels[i - 1] + 1) { issues.push('Heading hierarchy skip: h' + headingLevels[i - 1] + ' jumps to h' + headingLevels[i]); headingOk = false; }
}
if (headingOk && headingLevels.length > 0) passed.push('Heading hierarchy correct');
if (headingLevels.length === 0) warnings.push('No headings found');
const imgs = html.match(/<img[^>]*>/gi) || [];
let missingAlt = 0;
for (const img of imgs) { if (!/alt\s*=/i.test(img)) missingAlt++; }
if (missingAlt > 0) issues.push(missingAlt + ' image(s) missing alt attribute');
else if (imgs.length > 0) passed.push('All ' + imgs.length + ' images have alt attributes');
if (/@media[^{]*prefers-color-scheme\s*:\s*dark/i.test(html)) { passed.push('Dark mode @media query present'); } else { issues.push('No dark mode @media query found'); }
if (/color-scheme/i.test(html)) { passed.push('color-scheme meta present'); } else { warnings.push('Missing color-scheme meta tag'); }
if (/data-og[sc][cb]/i.test(html)) { passed.push('Outlook dark mode selectors present'); } else { warnings.push('Missing Outlook dark mode selectors'); }
const tables = html.match(/<table[^>]*>/gi) || [];
let tablesWithoutRole = 0;
for (const table of tables) { if (!/role\s*=\s*["']presentation["']/i.test(table)) tablesWithoutRole++; }
if (tablesWithoutRole > 0) warnings.push(tablesWithoutRole + ' table(s) missing role=presentation');
else if (tables.length > 0) passed.push('All tables have role=presentation');
const fontSizes = [...html.matchAll(/font-size\s*:\s*(\d+(?:\.\d+)?)\s*px/gi)];
let smallFonts = 0;
for (const fs of fontSizes) { if (parseFloat(fs[1]) < 14) smallFonts++; }
if (smallFonts > 0) warnings.push(smallFonts + ' font-size declaration(s) below 14px');
else if (fontSizes.length > 0) passed.push('All font sizes meet 14px minimum');
const links = [...html.matchAll(/<a[^>]*>([^<]*)<\/a>/gi)];
const badTexts = ['click here', 'read more', 'learn more', 'here', 'link', 'more', 'click'];
let badLinks = [];
for (const link of links) { const text = link[1].trim().toLowerCase(); if (badTexts.includes(text)) badLinks.push(link[1].trim()); }
if (badLinks.length > 0) warnings.push('Non-descriptive link text: ' + badLinks.join(', '));
else if (links.length > 0) passed.push('All links have descriptive text');
if (/<!DOCTYPE html>/i.test(html)) passed.push('DOCTYPE present'); else warnings.push('Missing DOCTYPE');
if (/meta[^>]*charset/i.test(html)) passed.push('Meta charset present'); else warnings.push('Missing meta charset');
if (/meta[^>]*viewport/i.test(html)) passed.push('Meta viewport present'); else warnings.push('Missing meta viewport');
if (/max-width|width\s*:\s*600/i.test(html)) passed.push('Email width constraint detected'); else warnings.push('No 600px max-width detected');
const status = issues.length === 0 ? 'ALL CHECKS PASSED' : 'ISSUES FOUND';
let report = 'ACCESSIBILITY & EMAIL TEST REPORT\n\nStatus: ' + status + '\nPassed: ' + passed.length + ' | Issues: ' + issues.length + ' | Warnings: ' + warnings.length + '\n\n';
if (passed.length > 0) report += 'PASSED:\n' + passed.map(p => '  + ' + p).join('\n') + '\n\n';
if (issues.length > 0) report += 'ISSUES (must fix):\n' + issues.map(i => '  - ' + i).join('\n') + '\n\n';
if (warnings.length > 0) report += 'WARNINGS (should fix):\n' + warnings.map(w => '  ! ' + w).join('\n') + '\n\n';
return report;

// Extract action from agent response
// Checks for :::SEND_START::: and :::SHIP_START::: markers

const agentOutput = $input.first().json.output || '';

// Check for SEND markers
const sendMatch = agentOutput.match(/:::SEND_START:::\s*([\s\S]*?)\s*:::SEND_END:::/);
if (sendMatch) {
  try {
    const payload = JSON.parse(sendMatch[1].trim());
    return [{
      json: {
        action: 'send',
        sendTo: payload.sendTo || '',
        subject: payload.subject || 'Email Preview',
        html: payload.html || '',
        htmlLength: (payload.html || '').length,
        extractedAt: new Date().toISOString()
      }
    }];
  } catch (e) {
    // Fallback: try extracting HTML directly
    const raw = sendMatch[1].trim();
    const htmlMatch = raw.match(/<!DOCTYPE[\s\S]*<\/html>/i);
    if (htmlMatch) {
      return [{
        json: {
          action: 'send',
          sendTo: '',
          subject: 'Email Preview',
          html: htmlMatch[0],
          htmlLength: htmlMatch[0].length,
          extractedAt: new Date().toISOString()
        }
      }];
    }
  }
}

// Check for SHIP markers
const shipMatch = agentOutput.match(/:::SHIP_START:::\s*([\s\S]*?)\s*:::SHIP_END:::/);
if (shipMatch) {
  try {
    const payload = JSON.parse(shipMatch[1].trim());
    return [{
      json: {
        action: 'ship',
        campaignName: payload.campaignName || 'Untitled Campaign',
        subject: payload.subject || '',
        html: payload.html || '',
        htmlLength: (payload.html || '').length,
        extractedAt: new Date().toISOString()
      }
    }];
  } catch (e) {
    const raw = shipMatch[1].trim();
    const htmlMatch = raw.match(/<!DOCTYPE[\s\S]*<\/html>/i);
    if (htmlMatch) {
      return [{
        json: {
          action: 'ship',
          campaignName: 'Untitled Campaign',
          subject: '',
          html: htmlMatch[0],
          htmlLength: htmlMatch[0].length,
          extractedAt: new Date().toISOString()
        }
      }];
    }
  }
}

// Check for TICKET markers
const ticketMatch = agentOutput.match(/:::TICKET_START:::\s*([\s\S]*?)\s*:::TICKET_END:::/);
if (ticketMatch) {
  try {
    const payload = JSON.parse(ticketMatch[1].trim());
    return [{
      json: {
        action: 'ticket',
        summary: payload.summary || 'Untitled Email',
        description: payload.description || '',
        epicKey: payload.epicKey || '',
        extractedAt: new Date().toISOString()
      }
    }];
  } catch (e) {
    return [{ json: { action: 'ticket', summary: 'Untitled Email', description: '', epicKey: '', extractedAt: new Date().toISOString() } }];
  }
}

// No markers — normal chat
return [{ json: { action: 'chat', output: agentOutput } }];
